        pipe_.InitBuffer(tmpQueue2_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue3_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue4_, 1, tileLen_ * sizeof(float));
    }

